// File: src/features/global.js
window.CookieSet = function (name, value, days) {
    days = days || 3; // Nilai default untuk `days`
    var expirationDate = new Date();
    expirationDate.setDate(expirationDate.getDate() + days);
    var cookieValue =
        name + "=" + value + "; expires=" + expirationDate.toUTCString();
    document.cookie = cookieValue;
};

window.CookieGet = function (name) {
    var cookies = document.cookie.split("; ");
    for (var i = 0; i < cookies.length; i++) {
        var cookie = cookies[i];
        var cookieParts = cookie.split("=");
        var cookieName = cookieParts[0];
        var cookieValue = cookieParts.slice(1).join("="); // Berguna jika value memiliki "="
        if (cookieName === name) {
            return cookieValue;
        }
    }
    return null;
};

window.redirect = function (url) {
    window.location.href = url;
};

