window.setLabelText = function (id, value) {
    var el = document.getElementById(id);
    if (!el) return;

    // fallback browser lama
    if (typeof el.textContent !== 'undefined') {
        el.textContent = value;
    } else {
        el.innerText = value;
    }
}

window.initStatus = function () {
    if (typeof statusConfig === 'undefined' || typeof statusStyle === 'undefined') {
        console.warn('Status config or style not found');
        return;
    }

    setLabelText('titleStatus', statusConfig.title.status);
    setLabelText('titleLogout', statusConfig.title.logout);
    setLabelText('labelConnectionInfo', statusConfig.labels.connectionInfo);

    // Dynamic Labels Update
    if (statusConfig.labels) {

        setLabelText('labelUsername', statusConfig.labels.username);
        setLabelText('labelTrial', statusConfig.labels.trial);
        setLabelText('labelIp', statusConfig.labels.ip);
        setLabelText('labelMac', statusConfig.labels.mac);
        setLabelText('labelUptime', statusConfig.labels.uptime);
        setLabelText('labelTimeLeft', statusConfig.labels.timeLeft);
        setLabelText('labelQuota', statusConfig.labels.quota);
        setLabelText('labelUpload', statusConfig.labels.upload);
        setLabelText('labelDownload', statusConfig.labels.download);
        setLabelText('labelExpired', statusConfig.labels.expired);
        setLabelText('labelRefresh', statusConfig.labels.refresh);


    }

    var logoutBtnLabel = document.getElementById('labelBtnLogout');
    if (logoutBtnLabel && statusConfig.buttons) {
        logoutBtnLabel.textContent = statusConfig.buttons.logout;
    }

    // Apply Styles from statusStyle

    // 1. Status Card Container - Tailwind: backdrop-blur-md rounded-xl shadow-lg
    var cardEl = document.querySelector('.bgStatus');
    if (cardEl && statusStyle.card) {
        if (statusStyle.card.background) cardEl.style.background = statusStyle.card.background;
        // Border style
        if (statusStyle.card.border && statusStyle.card.border.enabled) {
            cardEl.style.border = '1px solid ' + (statusStyle.card.border.color || '#d4af37');
        }
    }

    // 2. Title - Tailwind: text-2xl font-bold
    var titleEls = document.querySelectorAll('.titleStatus');
    if (titleEls.length && statusStyle && statusStyle.title) {
        for (var i = 0; i < titleEls.length; i++) {
            var el = titleEls[i];
            el.classList.add("text-2xl", "font-bold");
            if (statusStyle.title.color) {
                el.style.color = statusStyle.title.color;
            }
        }
    }

    var btnBgStatus = document.querySelectorAll(".btnBgStatus");
    for (var i = 0; i < btnBgStatus.length; i++) {
        btnBgStatus[i].style.color = statusStyle.button.color;

        var colors = statusStyle.button.gradient.join(', ');

        // PALING AMAN Android 5
        btnBgStatus[i].style.background =
            '-webkit-linear-gradient(top left, ' + colors + ')';

        // fallback modern
        btnBgStatus[i].style.background =
            'linear-gradient(45deg, ' + colors + ')';
    }


    // 4. Progress Bar (Quota)
    var progressBarContainer = document.querySelector('.st-progressbar-container');
    var progressBarFill = document.querySelector('.st-progressbar-fill');

    if (progressBarContainer) {
        if (statusStyle.progressBar && statusStyle.progressBar.background) {
            progressBarContainer.style.background = statusStyle.progressBar.background;
        }
    }

    if (progressBarFill && statusStyle.progressBar && statusStyle.progressBar.fillColor) {
        progressBarFill.style.background = statusStyle.progressBar.fillColor;
    }

    // 5. Stats Cards (Grid Items) - Tailwind: rounded-xl
    var statsCards = document.querySelectorAll('.st-stats-item');
    if (statsCards.length > 0 && statusStyle.stats) {
        for (var k = 0; k < statsCards.length; k++) {
            var card = statsCards[k];
            card.classList.add("rounded-xl");
            if (statusStyle.stats.background) card.style.background = statusStyle.stats.background;
            if (statusStyle.stats.color) card.style.color = statusStyle.stats.color;
        }
    }

    // 6. Traffic Stats Container - Tailwind: rounded-xl
    var trafficContainers = document.querySelectorAll('.st-traffic-card');
    if (trafficContainers.length && statusStyle && statusStyle.traffic) {
        for (var i = 0; i < trafficContainers.length; i++) {
            var el = trafficContainers[i];
            el.classList.add("rounded-xl");
            if (statusStyle.traffic.background) {
                el.style.background = statusStyle.traffic.background;
            }
            if (statusStyle.traffic.color) {
                el.style.color = statusStyle.traffic.color;
            }
        }
    }

}


