// File: src/features/network.js
window.initNetwork = function () {
    var modalPopup = document.getElementById('modalPopup');
    if (!modalPopup) return;

    var countdownTimer = null;
    var countdownValue = 5;
    var retryCount = 0;
    var isChecking = false;

    function checkInternet(manual) {
        if (isChecking) return;
        isChecking = true;

        var btn = document.getElementById('btnCekManual');
        var info = document.getElementById('infoCekManual');
        if (btn) btn.innerText = "Mengecek...";
        if (info && manual) info.innerText = "";

        stopTimers(); // Hentikan timer selama cek

        if (window.fetch) {
            fetch("https://eriiksanjaya.github.io/?_=" + new Date().getTime(), {
                mode: 'no-cors',
                cache: 'no-store'
            })
                .then(function () {
                    isChecking = false;
                    hideNoInternetModal();
                })
                .catch(function () {
                    isChecking = false;
                    handleCheckFail(manual);
                });
        } else {
            isChecking = false;
            if (!navigator.onLine) {
                handleCheckFail(manual);
            } else {
                hideNoInternetModal();
            }
        }
    }

    function handleCheckFail(manual) {
        retryCount++;

        // Jika modal sudah tampil
        if (!modalPopup.classList.contains('hidden') && document.getElementById('networkCountdown')) {
            var info = document.getElementById('infoCekManual');
            var btn = document.getElementById('btnCekManual');

            if (manual && info) {
                info.innerText = "Koneksi internet masih terputus.";

                setTimeout(() => {
                    info.innerText = "";
                }, 3000);

            } else if (info) {
                info.innerText = "";
            }
            if (btn) btn.innerText = "Cek Sekarang";

            var attemptEl = document.getElementById('retryCountEl');
            if (attemptEl) attemptEl.innerText = retryCount;

            countdownValue = 10;
            var countdownEl = document.getElementById('networkCountdown');
            if (countdownEl) countdownEl.innerText = countdownValue;

            startCountdown();
            return;
        }

        // Tampil pertama kali
        countdownValue = 5;
        var modalHtml =
            '<div class="fixed inset-0 flex items-center justify-center z-[99999] bg-black/95 px-4">' +
            '  <div class="bg-white rounded-3xl w-full max-w-sm overflow-hidden shadow-2xl flex flex-col items-center">' +
            '    <div class="bg-red-500 w-full p-6 pb-8 flex flex-col items-center justify-center text-white">' +
            '      <svg class="w-16 h-16 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>' +
            '      <h3 class="text-2xl font-bold text-center">Jaringan Gangguan</h3>' +
            '    </div>' +
            '    <div class="p-6 pt-0 mt-[-1rem] text-center w-full">' +
            '      <div class="bg-white rounded-2xl shadow-lg p-5 mb-5">' +
            '        <p class="text-[0.95rem] text-gray-700 leading-relaxed mb-1">Pusat jaringan internet saat ini sedang mengalami gangguan sementara dari provider.</p>' +
            '        <p class="text-[0.95rem] font-semibold text-gray-800">Mohon jangan panik 🙏</p>' +
            '        <p class="text-sm text-gray-500 mt-2">Koneksi akan normal dalam beberapa saat. Silakan tunggu atau cek ulang.</p>' +
            '      </div>' +
            '      <p class="text-sm font-medium text-gray-600 mb-1">Mencoba kembali dalam <span id="networkCountdown" class="font-bold text-red-500 text-base">' + countdownValue + '</span> detik...</p>' +
            '      <p class="text-xs text-gray-400 mb-4">(Percobaan menghubungkan ulang ke-<span id="retryCountEl">' + retryCount + '</span>)</p>' +
            '      <button id="btnCekManual" class="w-full bg-red-50 px-4 py-3 border border-red-200 text-red-600 hover:bg-red-500 hover:text-white font-semibold rounded-xl transition duration-300">Cek Sekarang</button>' +
            '      <p id="infoCekManual" class="text-xs font-semibold text-red-500 mt-3 min-h-[1rem]"></p>' +
            '    </div>' +
            '  </div>' +
            '</div>';

        modalPopup.innerHTML = modalHtml;
        modalPopup.classList.remove('hidden');

        var btn = document.getElementById('btnCekManual');
        if (btn) {
            btn.onclick = function () { checkInternet(true); };
        }

        startCountdown();
    }

    function hideNoInternetModal() {
        if (!modalPopup.classList.contains('hidden') && document.getElementById('networkCountdown')) {
            // Jika sudah terhubung lagi, reload halaman
            window.location.reload();
        }
    }

    function startCountdown() {
        stopTimers();
        var countdownEl = document.getElementById('networkCountdown');
        if (countdownEl) countdownEl.innerText = countdownValue;

        countdownTimer = setInterval(function () {
            if (isChecking) return;
            countdownValue--;

            if (countdownEl) {
                countdownEl.innerText = countdownValue;
            }

            if (countdownValue <= 0) {
                stopTimers();
                checkInternet(false);
            }
        }, 1000);
    }

    function stopTimers() {
        if (countdownTimer) {
            clearInterval(countdownTimer);
            countdownTimer = null;
        }
    }

    window.addEventListener('online', function () { checkInternet(true); });
    window.addEventListener('offline', function () { checkInternet(false); });

    // Cek inisialisasi awal
    checkInternet(false);
};


