// File: src/features/slider.js
window.initPromoSlider = function () {
    var container = document.getElementById('promo-slider-container');
    if (!container || typeof sliderConfig === 'undefined' || !sliderConfig.enabled) return;

    var slides = sliderConfig.images || [];
    if (slides.length === 0) return;

    // 1. Setup Slider HTML
    // Container Style: Relative needed? Not necessarily if dots are external.
    // But keeps it safe.
    // Container Style: Relative needed? Not necessarily if dots are external.
    // But keeps it safe.
    // container.style.position = 'relative'; // Removed to allow absolute positioning via CSS

    var html = '<div class="siema">';
    for (var i = 0; i < slides.length; i++) {
        var s = slides[i];
        html += '<img class="w-full rounded-xl shadow-xl" src="' + s.src + '" />';
    }
    html += '</div>';

    // Set container HTML
    container.innerHTML = html;

    // 2. Initialize Siema
    if (typeof Siema !== 'undefined') {
        var validSlides = slides.length;

        var mySiema = new Siema({
            selector: '.siema',
            duration: 500,
            easing: 'ease-out',
            perPage: 1,
            startIndex: 0,
            draggable: true,
            multipleDrag: true,
            threshold: 20,
            loop: true,
            rtl: false,
            onInit: function () { updateDots(this.currentSlide); },
            onChange: function () { updateDots(this.currentSlide); },
        });

        // 3. Generate Dots (External)
        // We inject a div AFTER the slider container
        var dotsContainerId = 'slider-dots-external';
        var dotsContainer = document.getElementById(dotsContainerId);

        // Create if not exists
        if (!dotsContainer) {
            dotsContainer = document.createElement('div');
            dotsContainer.id = dotsContainerId;
            // Flex center, margin top to separate from card/image
            dotsContainer.className = 'w-full flex justify-center space-x-2 z-10';

            // Insert after container
            if (container.parentNode) {
                container.parentNode.insertBefore(dotsContainer, container.nextSibling);
            }
        }

        // Render Dots
        if (dotsContainer) {
            var dotsHtml = '';
            // Get Colors from Config
            var dotColor = sliderStyle.dots.color;

            for (var i = 0; i < validSlides; i++) {
                dotsHtml += '<div class="slider-dot w-2 h-2 mt-1 rounded-full cursor-pointer transition-all duration-300" style="background-color: ' + dotColor + '" data-index="' + i + '"></div>';
            }
            dotsContainer.innerHTML = dotsHtml;

            // Add Click Listeners
            var dots = dotsContainer.querySelectorAll('.slider-dot');
            for (var i = 0; i < dots.length; i++) {
                (function (index) {
                    dots[index].addEventListener('click', function () {
                        var idx = parseInt(this.getAttribute('data-index'));
                        mySiema.goTo(idx);
                    });
                })(i);
            }
        }

        // 4. Update Dots State
        function updateDots(current) {
            if (!dotsContainer) return;
            var dots = dotsContainer.querySelectorAll('.slider-dot');

            var baseColor = sliderStyle.dots.color;
            var activeColor = sliderStyle.dots.activeColor;

            for (var i = 0; i < dots.length; i++) {
                var dot = dots[i];
                if (i === current) {
                    dot.style.backgroundColor = activeColor;
                    dot.classList.add('w-6');
                } else {
                    dot.style.backgroundColor = baseColor;
                    dot.classList.remove('w-6');
                }
            }
        }

        // 5. Auto Loop
        if (sliderConfig.delay > 0) {
            setInterval(function () {
                mySiema.next();
            }, sliderConfig.delay * 1000);
        }
    } else {
        console.warn("Siema library not found");
    }
}


