window.initLogin = function () {
    if (typeof loginConfig === 'undefined') return;

    var config = loginConfig;
    var labels = config.label;
    var styles = (typeof loginStyle !== 'undefined') ? loginStyle : {};

    // DOM Elements
    var textTitleF = document.getElementById('textTitleF');
    var textDescriptionF = document.getElementById('textDescriptionF');

    var labelForm = document.getElementById('labelForm');
    var voucherActive = document.getElementById('voucherActive');

    // Inputs Containers
    var domUsername = document.getElementById('domUsername');
    var domPassword = document.getElementById('domPassword');

    // Inputs
    var inputUser = document.getElementById('username');
    var inputPass = document.getElementById('password');

    // Icons Containers (Input Left)
    var iconInputUser = document.getElementById('iconInputUser');
    var iconInputUserPassword = document.getElementById('iconInputUserPassword');

    // Eye Icons (Input Right)
    var iconTypePasswordUser = document.getElementById('iconTypePasswordUser');
    var iconTypePassword = document.getElementById('iconTypePassword');

    var btnLogin = document.getElementById('btnLogin');
    var formLogin = document.getElementById('formLogin'); // Wrapper for Labels + Form

    var loginOpt = document.getElementById('loginOpt');
    var btnTrial = document.getElementById('btnTrial');
    var isTrialEl = document.getElementById('isTrial');

    var formTitle = document.getElementById('formTitle');

    // 1. STYLES APPLICATION

    // Card Style - Tailwind: backdrop-blur-md
    if (formLogin) {
        var cardContainer = formLogin.parentElement;
        if (cardContainer) {
            if (styles.card) {
                cardContainer.style.background = styles.card.background;
                // Add Tailwind backdrop-blur instead of inline style
                cardContainer.classList.add("backdrop-blur-sm");

                if (styles.card.border && styles.card.border.enabled) {
                    cardContainer.style.border = "1px solid " + styles.card.border.color;
                } else {
                    cardContainer.style.border = "none";
                }
            }
        }
    }

    // Title Style - Tailwind: text-xl font-bold
    if (labelForm && styles.title) {
        labelForm.classList.add("text-xl", "font-bold");
        labelForm.style.color = styles.title.color;
    }

    // Button Style - Tailwind: shadow-lg rounded-xl
    if (btnLogin && styles.button) {
        if (Array.isArray(styles.button.gradient)) {
            btnLogin.style.background = 'linear-gradient(to right, ' + styles.button.gradient[0] + ', ' + styles.button.gradient[1] + ')';
        } else {
            btnLogin.style.background = styles.button.gradient || '#6C5DD3';
        }
        btnLogin.style.color = styles.button.color;

        if (styles.button.border && styles.button.border.enabled) {
            btnLogin.style.border = "1px solid " + styles.button.border.color;
        } else {
            btnLogin.style.border = "none";
        }
    }

    // Input Styles (Border)
    function applyInputStyle(domEl) {
        if (!domEl) return;
        var inputDiv = domEl.querySelector('.input'); // The container with ring/border
        var placeholderEl = document.querySelector('.placeholder\\:text-slate-600') // The container with ring/border
        if (inputDiv && styles.input) {
            // Border
            if (styles.input.border) {
                if (styles.input.border.enabled) {
                    inputDiv.style.border = "1px solid " + styles.input.border.color;
                } else {
                    inputDiv.style.border = "none";
                }
            }
            // Background
            if (styles.input.background) {
                inputDiv.style.background = styles.input.background;
            }
        }
    }
    applyInputStyle(domUsername);
    applyInputStyle(domPassword);


    // 2. TABS & MENU (Single Menu Implementation)

    var currentMode = 'voucher';

    function updateTabs(mode) {
        // Toggle Logic
        var nextMode = mode === 'voucher' ? 'member' : 'voucher';
        var labelText = mode === 'voucher' ? labels.menu.member : labels.menu.voucher; // Show the OTHER option

        // Show Button
        if (loginOpt) {
            // Check if toggle allowed via config
            var canSwitch = false;
            if (config.optionLogin && config.optionLogin.enabled === 1) canSwitch = true;

            if (canSwitch) {
                loginOpt.classList.remove('hidden');
                // Added margin for Android 5 specific layout safety
                loginOpt.innerHTML = '<div class="text-lg font-medium" style="margin: 0 12px; color:' + (styles.menu ? styles.menu.color : '#9CA3AF') + '">' + labelText + '</div>';

                // Remove old listeners (cloning) to prevent stack
                var newBtn = loginOpt.cloneNode(true);
                if (loginOpt.parentNode) loginOpt.parentNode.replaceChild(newBtn, loginOpt);
                loginOpt = newBtn;

                loginOpt.onclick = function () { setMode(nextMode); };
            } else {
                if (loginOpt.parentNode) loginOpt.parentNode.removeChild(loginOpt);
            }
        }
    }

    // 3. LOGIC & TOGGLES

    // Case Enforcement
    function enforceCase(el, mode) {
        var setting = mode === 'voucher' ? config.voucher.value : config.member.value;
        var val = el.value;
        if (setting === 'upper') el.value = val.toUpperCase();
        if (setting === 'lower') el.value = val.toLowerCase();
    }

    // Auto-fill password in voucher mode
    if (inputUser) {
        inputUser.addEventListener('input', function () {
            enforceCase(inputUser, currentMode);

            // Voucher mode: password = username
            if (currentMode === 'voucher' && inputPass) {
                inputPass.value = inputUser.value;
                enforceCase(inputPass, currentMode);
            }
        });
    }

    if (inputPass) inputPass.addEventListener('input', function () { enforceCase(inputPass, currentMode); });

    // Icon & Input Type Logic
    function setupEyeToggle(iconContainer, inputEl) {
        var isVisible = true; // Default Open as requested

        function update() {
            var color = (styles.input && styles.input.icon) ? styles.input.icon : '#6C5DD3';
            if (isVisible) {
                inputEl.type = "text";
                iconContainer.innerHTML = IconEye(color); // Open Eye
            } else {
                inputEl.type = "password";
                iconContainer.innerHTML = IconEyeClosed(color); // Closed Eye
            }
        }

        iconContainer.onclick = function () {
            isVisible = !isVisible;
            update();
        };

        // Initialize
        update();
    }

    // Bind Toggles
    if (iconTypePasswordUser && inputUser) setupEyeToggle(iconTypePasswordUser, inputUser);
    if (iconTypePassword && inputPass) setupEyeToggle(iconTypePassword, inputPass);


    function setMode(mode) {
        currentMode = mode;
        updateTabs(mode);

        var iconColor = (styles.input && styles.input.icon) ? styles.input.icon : '#6C5DD3';

        // Logic to Show/Hide Inputs
        if (mode === 'voucher') {
            if (labelForm) labelForm.innerText = labels.title.voucher;
            if (voucherActive) voucherActive.value = "0";

            if (domUsername) domUsername.classList.remove('hidden');
            if (domPassword) domPassword.classList.add('hidden');

            if (inputUser) inputUser.placeholder = labels.form.voucher_placeholder;

            // Auto-fill password with username value in voucher mode
            if (inputPass && inputUser) {
                inputPass.value = inputUser.value;
            }

            // Render Left Icon
            if (iconInputUser) iconInputUser.innerHTML = IconUser(iconColor);

            // if (btnLogin) btnLogin.innerText = labels.button.login;

        } else if (mode === 'member') {
            if (labelForm) labelForm.innerText = labels.title.member;
            if (voucherActive) voucherActive.value = "1";

            if (domUsername) domUsername.classList.remove('hidden');
            if (domPassword) domPassword.classList.remove('hidden');

            if (inputUser) inputUser.placeholder = labels.form.member_placeholder;
            if (inputPass) {
                inputPass.placeholder = labels.form.password_placeholder;
                inputPass.value = ''; // Clear password when switching to member mode
            }

            if (iconInputUser) iconInputUser.innerHTML = IconUser(iconColor);
            if (iconInputUserPassword) iconInputUserPassword.innerHTML = IconPassword(iconColor);

        }
        if (btnLogin) btnLogin.innerText = labels.button.login;
    }

    // Initialization
    // Check config default
    var initial = config.defaultForm === 1 ? 'member' : 'voucher';

    setMode(initial);

    // Trial & Scan
    var isTrialEnabled = isTrialEl && isTrialEl.innerText.trim().toLowerCase() === 'yes';

    var btnLogInQrCode = document.getElementById('btnLogInQrCode');

    if (btnTrial) {
        if (isTrialEnabled) {
            btnTrial.classList.remove('hidden');
            btnTrial.innerHTML = '<div class="text-lg font-medium" style="margin: 0 12px; color:' + (styles.menu ? styles.menu.color : '#9CA3AF') + '">' + labels.menu.trial + '</div>';
            btnTrial.onclick = function () {
                var link = document.getElementById('linkTrial');
                if (link) window.location.href = link.href;
            };
        } else {
            if (btnTrial && btnTrial.parentNode) btnTrial.parentNode.removeChild(btnTrial);
        }
    }

    if (config.scan_qrcode && config.scan_qrcode.enabled) {
        if (btnLogInQrCode) {
            btnLogInQrCode.classList.remove('hidden');
            btnLogInQrCode.innerHTML = '<div class="text-lg font-medium" style="margin: 0 12px; color:' + (styles.menu ? styles.menu.color : '#9CA3AF') + '">' + labels.menu.scan + '</div>';
            btnLogInQrCode.onclick = function () {
                window.location.href = config.scan_qrcode.url;
            };
        }
    }

    function setPlaceholderColor(hexColor) {
        var css =
            '.input::-webkit-input-placeholder{color:' + hexColor + ' !important;}' +
            '.input::-moz-placeholder{color:' + hexColor + ' !important;}' +
            '.input::placeholder{color:' + hexColor + ' !important;}';

        var style = document.getElementById('dynamic-placeholder-style');

        if (!style) {
            style = document.createElement('style');
            style.id = 'dynamic-placeholder-style';
            style.type = 'text/css';
            document.head.appendChild(style);
        }

        style.innerHTML = css;
    }
    setPlaceholderColor(styles.input.placeholder);


}


// File: src/features/widget-rotator.js
window.initWidgetRotator = function () {
    // Ensure config exists
    var config = window.prayTimesConfig;
    if (typeof config === 'undefined') {
        console.error('Widget Rotator: prayTimesConfig is undefined');
        return;
    }

    // Determine active widgets explicitly
    var activeWidgets = [];
    if (config.praytimes && config.praytimes.enabled) activeWidgets.push('praytimes');
    if (config.date && config.date.enabled) activeWidgets.push('datetimes');

    var containers = {
        'praytimes': document.getElementById('prayer-times-container'),
        'datetimes': document.getElementById('datetimes-container')
    };

    var currentIndex = 0;

    function showWidget(index) {
        // If nothing active, hide all
        if (activeWidgets.length === 0) {
            for (var key in containers) {
                if (containers[key]) containers[key].style.display = 'none';
            }
            return;
        }

        // Hide all first
        for (var key in containers) {
            if (containers[key]) {
                containers[key].style.display = 'none';
            }
        }

        // Show current
        var key = activeWidgets[index];
        if (containers[key]) {
            containers[key].style.display = 'block';
        }
    }

    // Initial Show
    showWidget(currentIndex);

    // Only start interval if rotation needed (> 1)
    if (activeWidgets.length > 1) {
        setInterval(function () {
            currentIndex = (currentIndex + 1) % activeWidgets.length;
            showWidget(currentIndex);
        }, config.rotationDelay || 5000);
    }
};


